import java.nio.file.*;
import java.io.*;
import java.util.List;

public class FileReaderExample {
    public static void main(String[] args) throws IOException {
        // Define the path to the file
        Path filePath = Paths.get("scores.csv");

        // Read all lines at once into a List of Strings
        List<String> lines = Files.readAllLines(filePath);

        // Loop through each line and print it
        for (String line : lines) {
            System.out.println(line);
        }

        // Files.readAllLines handles closing automatically
        System.out.println("Read " + lines.size() + " lines.");
    }
}
// Expected output (assuming scores.csv exists):
// Alice,92
// Bob,78
// Charlie,88
// Read 3 lines.
